import React from 'react';
// Gerçək tətbiqdə: import { useQuery } from '@tanstack/react-query';

function ReactQueryExample() {
  // Mock useQuery
  const { data, isLoading, error } = {
    data: { id: 1, title: 'React Query Öyrən' },
    isLoading: false,
    error: null
  };

  if (isLoading) return <p>Yüklənir...</p>;
  if (error) return <p>Xəta: {error.message}</p>;

  return <p>Başlıq: {data.title}</p>;
}

console.log('React Query ilə komponent yaradıldı');

